import React, { useEffect, useRef } from 'react';
import { gsap } from 'gsap';
import './Hero.css';

const Hero = () => {
  const heroRef = useRef(null);
  const titleRef = useRef(null);
  const subtitleRef = useRef(null);
  const ctaRef = useRef(null);
  const statsRef = useRef(null);
  const diamondRef = useRef(null);
  const bgLinesRef = useRef(null);

  useEffect(() => {
    const ctx = gsap.context(() => {
      // Staggered entrance
      const tl = gsap.timeline({ delay: 0.3 });

      // BG lines
      tl.fromTo('.bg-line', 
        { scaleY: 0, transformOrigin: 'bottom' },
        { scaleY: 1, duration: 1.2, stagger: 0.1, ease: 'power3.out' },
        0
      );

      // Diamond logo
      tl.fromTo(diamondRef.current,
        { scale: 0, rotation: -45, opacity: 0 },
        { scale: 1, rotation: 0, opacity: 1, duration: 1.2, ease: 'back.out(1.7)' },
        0.3
      );

      // Title chars
      tl.fromTo('.hero-label',
        { opacity: 0, x: -40 },
        { opacity: 1, x: 0, duration: 0.8, ease: 'power3.out' },
        0.6
      );

      tl.fromTo('.title-line',
        { y: 120, opacity: 0, skewY: 5 },
        { y: 0, opacity: 1, skewY: 0, duration: 1, stagger: 0.15, ease: 'power4.out' },
        0.7
      );

      tl.fromTo(subtitleRef.current,
        { opacity: 0, y: 20 },
        { opacity: 1, y: 0, duration: 0.8, ease: 'power3.out' },
        1.3
      );

      tl.fromTo(ctaRef.current,
        { opacity: 0, y: 20 },
        { opacity: 1, y: 0, duration: 0.8, ease: 'power3.out' },
        1.5
      );

      tl.fromTo('.stat-item',
        { opacity: 0, y: 30 },
        { opacity: 1, y: 0, duration: 0.6, stagger: 0.15, ease: 'power3.out' },
        1.6
      );

      // Floating diamond animation
      gsap.to(diamondRef.current, {
        y: -15,
        duration: 3,
        repeat: -1,
        yoyo: true,
        ease: 'sine.inOut',
        delay: 2
      });

      // Rotating outer ring
      gsap.to('.diamond-ring', {
        rotation: 360,
        duration: 20,
        repeat: -1,
        ease: 'linear',
        transformOrigin: 'center center'
      });

      // Scroll indicator bounce
      gsap.to('.scroll-indicator', {
        y: 10,
        duration: 1.5,
        repeat: -1,
        yoyo: true,
        ease: 'sine.inOut',
        delay: 3
      });

    }, heroRef);

    return () => ctx.revert();
  }, []);

  return (
    <section id="home" ref={heroRef} className="hero">
      {/* Background lines */}
      <div ref={bgLinesRef} className="bg-lines">
        {[...Array(8)].map((_, i) => (
          <div key={i} className="bg-line" style={{ left: `${12.5 * i}%` }} />
        ))}
      </div>

      {/* Gradient overlay */}
      <div className="hero-gradient" />

      {/* Content */}
      <div className="hero-content">
        <div className="hero-left">
